import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"50. Public Holidays","description":"","frontmatter":{"title":"50. Public Holidays","eba":"Biomedical Engineers 2025-2028","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/50-public-holidays.md","filePath":"ebas/biomedical-engineers/leave/50-public-holidays.md"}'),i={name:"ebas/biomedical-engineers/leave/50-public-holidays.md"};function s(l,e,n,h,p,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_50-public-holidays" tabindex="-1">50. Public Holidays <a class="header-anchor" href="#_50-public-holidays" aria-label="Permalink to &quot;50. Public Holidays&quot;">​</a></h1><p><strong>50.1</strong> Entitlement to be absent with pay</p><p><strong>(a)</strong> An Employee is entitled to be absent from their employment on a day or part-day that is a public holiday in the place where the Employee is based for work purposes.</p><p><strong>(b)</strong> However, the Employer may request an Employee to work on a public holiday if the request is reasonable. If the Employer requests an Employee to work on a public holiday, in accordance with the NES, the Employee may refuse the request if:</p><p><strong>(i)</strong> the request is not reasonable; or</p><p><strong>(ii)</strong> the refusal is reasonable.</p><p><strong>(c)</strong> If, in accordance with the NES, an Employee is absent from their employment on a day or part-day that is a public holiday the Employer must:</p><p><strong>(i)</strong> pay the Employee at the Employee&#39;s ordinary time rate of pay for the Employee’s ordinary hours of work on the day or part-day that the Employee is absent from their employment;</p><p><strong>(ii)</strong> continue to accrue leave on the ordinary hours of work on the day or part day that the Employee is absent from their employment; Note: If the Employee does not have ordinary hours of work on the public holiday, the employee is not entitled to payment under the NES (subject to subclause 50.6). For example, the Employee is not entitled to payment if the Employee is a casual employee who is not rostered on for the public holiday, or is a part-time employee whose part-time hours do not include the day of the week on which the public holiday occurs.</p><p><strong>(d)</strong> The provisions of subclause 50.1(c) apply where the Employee is absent from their employment for part of their ordinary hours on the day or part-day that is a public holiday.</p><p>Example 1:</p><p>A part-time Employee is requested to work four (4) ordinary hours on the public holiday. If it was not for the public holiday, the Employee’s ordinary hours would have been eight (8) on the day. The Employee is still entitled to their ordinary time rate of pay for the four (4) ordinary hours the Employee was not requested to work by the Employer. They will also accrue leave on what would have been their eight (8) ordinary hours on the day.</p><p>Example 2:</p><p>A full-time Employee is required to be on-call on the public holiday. If it was not for the public holiday, the Employee’s ordinary hours would have been eight (8) on the day. The Employee is called in to work three (3) hours of overtime during what would have been part of their ordinary hours. The Employee is still entitled to their ordinary time rate of pay for the five (5) ordinary hours the Employee was</p><p>not recalled to work by the Employer. They will also accrue leave on what would have been their eight (8) ordinary hours on the day.</p><p><strong>50.2</strong> Prescribed public holidays The public holidays to which this clause applies are the days in respect of the following occasions:</p><p><strong>(a)</strong> New Year’s Day, Good Friday, Easter Saturday, Easter Monday, Christmas Day and Boxing Day; and</p><p><strong>(b)</strong> The following days, as prescribed in the relevant States, Territories and localities: Australia Day, Easter Sunday, Anzac Day, King’s Birthday, Friday before the AFL Grand Final and Labour Day; and</p><p><strong>(c)</strong> Melbourne Cup Day or in lieu of Melbourne Cup, some other day as determined in a particular locality; and</p><p><strong>(d)</strong> Any additional public holiday declared or prescribed in Victoria or a locality in respect of any occasion other than those set out in clause 50.2(a)– 50.2(c) above.</p><p><strong>50.3</strong> Public holidays in lieu Where Christmas Day, Australia Day, Boxing Day or New Year’s Day (Actual Day) is a Saturday or Sunday, and a substitute holiday/day in lieu is determined under Victorian law on another day in respect of those occasions (Other Day) the public holiday benefits will be observed on the other day, For the avoidance of doubt the public holiday benefits will be observed on the day determined under Victorian law for each occasion not the Actual Day.</p><p><strong>50.4</strong> Substitution of public holidays by agreement</p><p><strong>(a)</strong> An Employer and Employee may agree to substitute another day for a day that would otherwise be a public holiday under the NES or this Agreement.</p><p><strong>(b)</strong> An agreement pursuant to subclause 50.4(a) shall be recorded in writing and a copy given to the Employee.</p><p><strong>50.5</strong> Public holiday benefit for time worked on a public holiday</p><p><strong>(a)</strong> If an Employee works (excluding recall) on any such holiday, they will:</p><p><strong>(i)</strong> be paid at the rate of 200% of the weekly wage prescribed at <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> for the time worked with a minimum of four hours wages; or</p><p><strong>(ii)</strong> by mutual agreement, be entitled to time off equivalent to the hours worked with a minimum of four hours time off without loss of pay; such time off shall be taken at a time mutually convenient to the Employer and the Employee within one month of the day on which the Employee worked; or by mutual agreement, where an Employee is entitled to a full working day off, such time off may be added to the Employee’s annual leave balance.</p><p><strong>(b)</strong> An Employee who is recalled to duty and works on any such holiday shall be paid from the time of receiving the recall until the time of finishing such recall with a minimum of three hours payment for each such recall at 200% of the weekly wage prescribed at <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>.</p><p><strong>50.6</strong> Public holiday benefit for public holiday occurring on Employee’s rostered day off</p><p><strong>(a)</strong> Subject to subclause 50.6(c), where a public holiday is observed on a full-time Employee’s rostered day off the full-time Employee shall be entitled to receive one day’s pay in addition to the weekly wage or one day off at a time convenient to the Employer without loss of pay in lieu thereof.</p><p><strong>(b)</strong> Subject to subclause 50.6(c), where a public holiday is observed on a part-time Employee’s rostered day off the Employer must review the roster pattern of the Employee over the preceding six months. If the review shows that the Employee has worked over 50% or more on the days which the particular public holiday is observed, the Employee shall be entitled to receive a pro-rata payment according to the following formula. Example:</p><p>Average Applicable Base Total Penalty Hours Shift Length Payment Payment 24 hours X 8 hours 5.05 hours Times by 1 5.05 38 hours</p><p>NOTE: The above is an illustrative example only. To calculate the average weekly hours Employers must review the rosters over the previous six months. In addition, the shift length used in the calculation should be appropriate to the shift that is normally worked by the Employee.</p><p><strong>(c)</strong> If a public holiday is observed on a Saturday or Sunday then subclauses 50.6(a) and 50.6(b) will only apply for weekend workers. For the purpose of this clause a weekend worker is an Employee who regularly works ordinary hours on a Saturday or Sunday.</p><p><strong>(d)</strong> Rostered day off for a Biomedical Engineer for the purpose of this clause is a day in which the Employee is not rostered for duty for the relevant roster period. This is distinct from clause 50.1 in which an Employee is normally rostered but given the day off.</p><p>Plain language terms: public holiday pay.</p>',37)])])}const c=o(i,[["render",s]]);export{u as __pageData,c as default};
